package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;

import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class TripleStoreFanOutStatsTest {

	@TempDir
	File dataDir;

	private TripleStore tripleStore;

	@BeforeEach
	void setUp() throws Exception {
		tripleStore = new TripleStore(dataDir, new LmdbStoreConfig("spoc,posc"), null);
	}

	@AfterEach
	void tearDown() throws Exception {
		tripleStore.close();
	}

	@Test
	void individualWritesDuplicatesAndRemovalsMaintainCounts() throws Exception {
		tripleStore.startTransaction();
		assertThat(tripleStore.storeTriple(1, 7, 101, 0, true)).isTrue();
		assertThat(tripleStore.storeTriple(1, 7, 102, 0, true)).isTrue();
		assertThat(tripleStore.storeTriple(1, 7, 102, 0, true)).isFalse();
		tripleStore.commit();

		assertThat(tripleStore.meanFanOut(7, true, true).orElseThrow()).isBetween(1.8D, 2.2D);

		tripleStore.startTransaction();
		tripleStore.removeTriplesByContext(1, 7, 101, 0, true, ignored -> {
		});
		tripleStore.commit();

		assertThat(tripleStore.meanFanOut(7, true, true).orElseThrow()).isBetween(0.8D, 1.2D);
	}

	@Test
	void alignedWritesMaintainFanOutStatistics() throws Exception {
		long[] subjects = { 1, 2, 3, 4 };
		long[] predicates = { 9, 9, 9, 9 };
		long[] objects = { 101, 102, 103, 104 };
		long[] contexts = { 0, 0, 0, 0 };

		tripleStore.startTransaction();
		tripleStore.storeTriplesAligned(subjects, predicates, objects, contexts, subjects.length, true);
		tripleStore.commit();

		assertThat(tripleStore.meanFanOut(9, true, true).orElseThrow()).isBetween(0.8D, 1.2D);
		assertThat(tripleStore.meanFanOut(9, false, true).orElseThrow()).isBetween(0.8D, 1.2D);
	}

	@Test
	void rollbackDropsUncommittedAdvisoryObservations() throws Exception {
		tripleStore.startTransaction();
		tripleStore.storeTriple(1, 11, 101, 0, true);
		tripleStore.rollback();

		assertThat(tripleStore.meanFanOut(11, true, true)).isEmpty();
	}
}
